class BookMyShow {
public:
    BookMyShow(int n, int m) : n(n), m(m), rows(n, vector<int>(m, 0)) {}

    vector<int> gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; ++i) {
            int consecutive = 0;
            for (int j = 0; j < m; ++j) {
                if (rows[i][j] == 0) {
                    consecutive++;
                    if (consecutive == k) {
                        for (int x = j - k + 1; x <= j; ++x) {
                            rows[i][x] = 1;
                        }
                        return {i, j - k + 1};
                    }
                } else {
                    consecutive = 0;
                }
            }
        }
        return {};
    }

    bool scatter(int k, int maxRow) {
        int count = 0;
        for (int i = 0; i <= maxRow; ++i) {
            int available = 0;
            for (int j = 0; j < m; ++j) {
                if (rows[i][j] == 0) {
                    available++;
                }
            }
            count += available;
            if (count >= k) {
                int remaining = k;
                for (int j = 0; j < m && remaining > 0; ++j) {
                    if (rows[i][j] == 0) {
                        rows[i][j] = 1;
                        remaining--;
                    }
                }
                if (remaining > 0) {
                    for (int x = i + 1; x <= maxRow && remaining > 0; ++x) {
                        for (int j = 0; j < m && remaining > 0; ++j) {
                            if (rows[x][j] == 0) {
                                rows[x][j] = 1;
                                remaining--;
                            }
                        }
                    }
                }
                return true;
            }
        }
        return false;
    }

private:
    int n;
    int m;
    vector<vector<int>> rows;
};

